# Custom JSON encoder/decoder for complex data structures
class SafeEncoder(json.JSONEncoder):
    """Handles complex Python types without using pickle."""
    def default(self, obj):
        if isinstance(obj, (datetime, date)):
            return {"__type__": "datetime", "value": obj.isoformat()}
        if isinstance(obj, Decimal):
            return {"__type__": "Decimal", "value": str(obj)}
        if isinstance(obj, bytes):
            import base64
            return {"__type__": "bytes", "value": base64.b64encode(obj).decode("ascii")}
        if isinstance(obj, set):
            return {"__type__": "set", "value": list(obj)}
        if isinstance(obj, frozenset):
            return {"__type__": "frozenset", "value": list(obj)}
        if hasattr(obj, "__dict__"):
            return {"__type__": "object", "class": obj.__class__.__name__, "value": obj.__dict__}
        return super().default(obj)


def safe_decoder(obj: Dict) -> Any:
    """Reconstruct complex types from JSON-safe representations."""
    if "__type__" not in obj:
        return obj
    type_tag = obj["__type__"]
    value = obj["value"]
    if type_tag == "datetime":
        return datetime.fromisoformat(value)
    if type_tag == "Decimal":
        return Decimal(value)
    if type_tag == "bytes":
        import base64
        return base64.b64decode(value)
    if type_tag == "set":
        return set(value)
    if type_tag == "frozenset":
        return frozenset(value)
    if type_tag == "object":
        # Only reconstruct known/allowed types
        return obj  # Return as dict - don't instantiate arbitrary classes
    return obj


def serialize_job(job_data: dict) -> str:
    """Serialize job data safely using JSON. Use this when enqueuing messages."""
