def main(msg: func.ServiceBusMessage) -> None:
    """
    Azure Function triggered by Service Bus queue messages.
    
    Expects JSON messages with structure:
    {
        "job_type": "data_transform",
        "job_id": "unique-id",
        "payload": { ... },
        "created_at": "2024-01-01T00:00:00"
    }
    """
    message_id = msg.message_id
    logging.info("Received Service Bus message: %s", message_id)

    try:
        # SECURE: Deserialize using JSON, NOT pickle
        message_body = msg.get_body().decode("utf-8")
        job_data = deserialize_job(message_body)

        # Validate message structure
        if not isinstance(job_data, dict):
            raise ValueError("Message must be a JSON object")

        job_type = job_data.get("job_type")
        job_id = job_data.get("job_id")
        payload = job_data.get("payload", {})

        if not job_type or not job_id:
            raise ValueError("Message must contain 'job_type' and 'job_id'")

        # Validate job type against allowlist
        if job_type not in ALLOWED_JOB_TYPES:
            raise ValueError(
                f"Unknown job_type '{job_type}'. Allowed: {ALLOWED_JOB_TYPES}"
            )

        logging.info(
            "Processing job: type=%s, id=%s, message_id=%s",
            job_type, job_id, message_id
        )

        # Dispatch to appropriate handler
        handler = JOB_HANDLERS[job_type]
        result = handler(payload)

        logging.info(
            "Job completed: type=%s, id=%s, result=%s",
            job_type, job_id, result.get("status")
        )

    except json.JSONDecodeError as e:
        logging.error(
            "Failed to decode message %s as JSON: %s", message_id, str(e)
        )
        raise  # Let Service Bus handle retry/dead-letter

    except ValueError as e:
        logging.error(
            "Invalid message %s: %s", message_id, str(e)
        )
        raise

    except Exception as e:
        logging.exception(
            "Unexpected error processing message %s: %s", message_id, str(e)
        )
        raise


